const _faiths = {title: "Deities and Faiths", jsx: <IonList lines="full"><IonItem className="mainItem basic"><IonLabel><p>Deities and Faiths are presented in stat blocks that follow <Link to="/rule/reading_a_deity_stat_block">this format</Link>.</p>
<p>In addition, other information related to that deity or faith may be presented. This includes:</p>
<ul>
<li>The code of conduct for a paladin</li>
<li>The conduct required for an "Obedience" feat, such as <Link to="/feat/deific_obedience">Deific Obedience</Link> or <Link to="/feat/fiendish_obedience">Fiendish Obedience</Link><ul>
<li>Any boons related to prestige classes that use such Obediences, such as <Link to="/pclass/evangelist">Evangelist</Link>, <Link to="/pclass/mystery_cultist">Mystery Cultist</Link>, or <Link to="/pclass/demoniac">Demoniac</Link></li>
</ul>
</li>
<li>Any <Link to="/ability/inquisitions">inquisitions</Link> the deity may be associated with</li>
<li>Details of any <Link to="/feat/divine_fighting_technique">Divine Fighting Technique</Link> the deity may have</li>
<li>Archetypes, prestige classes, traits, spells, feats, magic items, and monsters that are related to the deity or faith</li>
<li>Any unique spell rules that apply to certain classes (such as gaining a spell at an early level, or gaining a spell from outside the class's spell list)</li>
<li>Any additional monsters that can be called by a <em>summon</em> spell</li>
</ul>
</IonLabel></IonItem><MainLink to="/main/faiths_all" endem="(463 deities/faiths)" info="View All Deities" /><MainLink to="/main/faiths_pantheons" info="View Deities by Pantheon" /><MainLink to="/main/faiths_alignments" info="View Deities by Alignment" /><MainLink to="/main/faiths_domains" info="View Deities by Domain" /><MainLink to="/main/faiths_subdomains" info="View Deities by Subdomain" /></IonList>};
